  '3 of Cups': { title: 'Señor de la Abundancia', description: 'Celebración, amistad y el compartir gozoso de la abundancia emocional.', reversed: 'Aislamiento social, exclusión o excesos que agrian la celebración. Chismes dentro del grupo de amigos, conexiones superficiales o la resaca después de la fiesta.' },
  '4 of Cups': { title: 'Señor del Lujo o del Placer Mezclado', description: 'Contemplación, reevaluación y posible insatisfacción a pesar de la seguridad emocional.', reversed: 'Emerger de la apatía y reconocer nuevas oportunidades. Alternativamente, un repliegue más profundo en el descontento: dejar pasar lo que se ofrece porque la depresión o el cinismo han cerrado los ojos.' },
  '5 of Cups': { title: 'Señor de la Pérdida en el Placer', description: 'Decepción, pérdida emocional, pero con esperanza si miras más allá de las copas derramadas.', reversed: 'Comenzar a recuperarse del duelo, volverse hacia lo que queda. Aceptación después de la pérdida, o los primeros pasos hacia la renovación emocional. Las copas que siguen en pie finalmente entran en foco.' },
  '6 of Cups': { title: 'Señor del Placer', description: 'Nostalgia, felicidad inocente y la alegría pura de compartir con otros.', reversed: 'Vivir en el pasado a expensas del presente. Aferrarse a la infancia o la nostalgia como escape, asuntos no resueltos de la vida temprana que resurgen, o la incapacidad de avanzar porque el pasado se siente más seguro.' },
  '7 of Cups': { title: 'Señor del Éxito Ilusorio', description: 'Elecciones, fantasías y la necesidad de distinguir entre sueños y realidad.', reversed: 'Claridad que emerge de la confusión, o parálisis por demasiadas opciones. Las ilusiones se desvanecen: ya sea una confrontación aleccionadora con la realidad o un bienvenido regreso a la toma de decisiones con los pies en la tierra.' },
  '8 of Cups': { title: 'Señor del Éxito Abandonado', description: 'Seguir adelante, buscar un significado más profundo y dejar atrás lo que ya no sirve.', reversed: 'Miedo a dejar lo familiar, incluso cuando ya no nutre. Vagar sin rumbo ni propósito, regresar a situaciones ya superadas, o la incapacidad de comprometerse con la partida necesaria.' },
  '9 of Cups': { title: 'Señor de la Felicidad Material', description: 'Contentamiento, satisfacción emocional y el cumplimiento de los deseos.', reversed: 'Deseos cumplidos que no traen satisfacción, o suficiencia confundida con contentamiento. Excesos, materialismo sustituyendo la plenitud emocional genuina, o el vacío persistente detrás de la sonrisa satisfecha.' },
  '10 of Cups': { title: 'Señor del Éxito Perpetuo', description: 'Armonía, felicidad duradera y el logro de la plenitud emocional.', reversed: 'Discordia doméstica, lazos familiares rotos o el ideal de felicidad que no puede sostenerse en la realidad. El arcoíris se desvanece, revelando tensiones no resueltas bajo la superficie de la imagen perfecta.' },

